import pytest
import requests

def test_unauthenticated_delete_returns_401(admin_token, base_url, create_onboarding_task):
    task_id = create_onboarding_task(admin_token)

    resp = requests.delete(
        f"{base_url}/api/onboarding-tasks/{task_id}",
    )

    assert resp.status_code == 401, (
        f"Expected 401 Unauthorized, got {resp.status_code}: {resp.text}"
    )

import pytest
import requests

def test_delete_already_deleted_task_returns_boundary_status(
    admin_token, base_url, create_onboarding_task
):
    task_id = create_onboarding_task(admin_token)
    headers = {"Authorization": f"Bearer {admin_token}"}
    url = f"{base_url}/api/onboarding-tasks/{task_id}"

    first = requests.delete(url, headers=headers)
    assert first.status_code in (200, 201), (
        f"First delete expected 200/201, got {first.status_code}"
    )

    second = requests.delete(url, headers=headers)
    assert second.status_code in (404, 410), (
        f"Second delete expected 404 or 410, got {second.status_code}: {second.text}"
    )

