import pytest
import requests

def test_audit_record_written_after_delete(
    admin_token, base_url, create_onboarding_task, get_audit_records
):
    task_id = create_onboarding_task(admin_token)
    headers = {"Authorization": f"Bearer {admin_token}"}

    resp = requests.delete(
        f"{base_url}/api/onboarding-tasks/{task_id}",
        headers=headers,
    )
    assert resp.status_code in (200, 201), (
        f"Expected 200/201, got {resp.status_code}: {resp.text}"
    )

    audit_entries = get_audit_records(
        entity_id=task_id,
        action="delete",
        token=admin_token,
    )
    assert len(audit_entries) >= 1, (
        f"Expected at least one audit record for task {task_id}, got {audit_entries}"
    )
    actions = [e.get("action", "").lower() for e in audit_entries]
    assert any("delete" in a for a in actions), (
        f"No DELETE audit action found; recorded actions: {actions}"
    )
